#include<bits/stdc++.h>
using namespace std;
long long  c[2005][2005], dp[2005][2005];
int t, mod = 10007, n, m, a, b, k;
void init() {
	c[0][0] = 1;
	c[1][0] = 1;
	c[1][1] = 1;
	for (int i = 2; i <= 1005; i++) {
		c[i][0] = 1;
		for (int j = 1; j <= i; j++) {
			c[i][j] = (c[i - 1][j - 1] + c[i - 1][j]) % mod;
		}
	}
}
int main() {
	cin >> a >> b >> k >> n >> m;
	init();
	long long aans = 1, bans = 1;
	for (int i = 1; i <= n; i++) {
		aans *= a;
		aans %= mod;
	}
	for (int i = 1; i <= m; i++) {
		bans *= b;
		bans %= mod;
	}
	cout<<((c[k][n]*aans)%mod*bans)%mod;
	return 0;
}
